32	};
33	const BLOCK_OF_3_PRICE = 60;
34	const BLOCK_ELIGIBLE_TYPES = new Set(["rune", "moonstone"]);
35	const HIGH_ENCHANTMENT_THRESHOLD = 5;
36	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
37	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
38	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
39	const CURSE_SURCHARGE_RATE = 0.5;
40	const LOYALTY_THRESHOLD_YEARS = 2;
41	const LOYALTY_DISCOUNT_RATE = 0.2;
42	const FIRST_INSURANCE_RATE = 0.1;
43	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
