45	function quotePremium(
46	  items: Item[],
47	  yearsWithMHPCO: number,
48	  quoteIndex: number,
49	): number {
50	  const countsByType: Record<string, number> = {};
51	  for (const item of items) {
52	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
53	  }
54	  let policyBase = 0;
55	  for (const [type, count] of Object.entries(countsByType)) {
56	    if (BLOCK_ELIGIBLE_TYPES.has(type) && count === 3) {
57	      policyBase += BLOCK_OF_3_PRICE;
58	    } else {
59	      policyBase += count * BASE_PREMIUM_BY_ITEM_TYPE[type];
60	    }
61	  }
62	  let itemSurcharges = 0;
63	  for (const item of items) {
64	    let surchargeRate = 0;
65	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
66	      surchargeRate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
67	    }
68	    if (item.cursed) {
69	      surchargeRate += CURSE_SURCHARGE_RATE;
70	    }
71	    itemSurcharges += surchargeRate * BASE_PREMIUM_BY_ITEM_TYPE[item.type];
72	  }
73	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
74	  const loyaltyDiscount =
75	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
76	  const followUpDiscount = quoteIndex >= 1 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
77	  return (
78	    Math.ceil(
79	      policyBase + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount,
80	    ) + PROCESSING_FEE
81	  );
82	}
