84	function adjustForEnchantment(amount: number, insuredItem: Item | undefined): number {
85	  if ((insuredItem?.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD) {
86	    return amount * HIGH_ENCHANTMENT_PAYOUT_RATE;
87	  }
88	  return amount;
