92	  claimStep: Step,
93	  steps: Step[],
94	  remainingCapByPolicy: Record<number, number>,
95	): { payout: number; remainingCap: number } {
96	  const policyIndex = claimStep.policy!;
97	  const policyItems = steps[policyIndex].items ?? [];
98	  if (!(policyIndex in remainingCapByPolicy)) {
99	    const insuranceSum = policyItems.reduce(
100	      (sum, item) => sum + INSURANCE_VALUE_BY_ITEM_TYPE[item.type],
101	      0,
102	    );
103	    remainingCapByPolicy[policyIndex] = CAP_MULTIPLIER * insuranceSum;
104	  }
105	  const damages = claimStep.incident?.damages ?? [];
106	  const grossPayout = damages.reduce((sum, damage) => {
107	    const insuredItem = policyItems.find((item) => item.type === damage.itemType);
108	    const reimbursableAmount = adjustForEnchantment(damage.amount, insuredItem);
109	    return sum + Math.max(0, reimbursableAmount - DEDUCTIBLE_PER_DAMAGE);
110	  }, 0);
111	  const payout = Math.min(
112	    Math.floor(grossPayout),
113	    remainingCapByPolicy[policyIndex],
114	  );
115	  remainingCapByPolicy[policyIndex] -= payout;
116	  return { payout, remainingCap: remainingCapByPolicy[policyIndex] };
117	}
