119	export function processScenario(scenario: unknown): unknown {
120	  const { customer, steps } = scenario as Scenario;
121	  const yearsWithMHPCO = customer?.yearsWithMHPCO ?? 0;
122	  const remainingCapByPolicy: Record<number, number> = {};
123	  let quoteIndex = 0;
