125	    if (step.op === "claim") {
126	      return processClaim(step, steps, remainingCapByPolicy);
127	    }
128	    const premium = quotePremium(step.items ?? [], yearsWithMHPCO, quoteIndex);
129	    quoteIndex += 1;
130	    return { premium };
131	  });
132	  return { results };
